import IdentityShell from "@/components/IdentityShell";
import ConcentricCore from "@/components/ConcentricCore";
import SystemState from "@/components/SystemState";
import styles from "./page.module.css";
import { getAgentStatus, getMemoryStats, runAgentTask, queryMemory, getIdentityInfo } from "@/lib/api";
import { useState, useEffect } from "react";

interface BackendStatus {
  status: string;
  layer: string;
  user?: string; // Agent status might not always return user
}

interface MemoryStatus {
  total_entries: number;
  layer: string;
}

interface IdentityStatus {
  id: string;
  status: string;
  layer: string;
}

export default function Home() {
  const [agentStatus, setAgentStatus] = useState<BackendStatus | null>(null);
  const [memoryStatus, setMemoryStatus] = useState<MemoryStatus | null>(null);
  const [identityStatus, setIdentityStatus] = useState<IdentityStatus | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchStatus = async () => {
      try {
        setLoading(true);
        // Fetching multiple statuses in parallel
        const [agentData, memoryData, identityData] = await Promise.all([
          getAgentStatus(),
          getMemoryStats(),
          getIdentityInfo(),
        ]);
        setAgentStatus(agentData);
        setMemoryStatus(memoryData);
        setIdentityStatus(identityData);
      } catch (err: any) {
        console.error("Failed to fetch backend status:", err);
        setError(err.message || "Could not connect to backend services.");
      } finally {
        setLoading(false);
      }
    };

    fetchStatus();
  }, []);

  // Placeholder for running a task - can be triggered by a button later
  const handleRunTask = async () => {
    try {
      // Example task
      const response = await runAgentTask("Explain the OmegA architecture briefly.");
      console.log("Agent task response:", response);
      alert(`Agent task completed! Response: ${response.response}`);
    } catch (err: any) {
      console.error("Failed to run agent task:", err);
      alert(`Agent task failed: ${err.message}`);
    }
  };

  return (
    <main className={styles.main}>
      <IdentityShell />

      <section className={styles.hero}>
        <ConcentricCore />
        <SystemState />
      </section>

      <section className={styles.intro}>
        <div className={styles.introGrid}>
          <div className={`${styles.card} glass`}>
            <h3>Sovereign Identity</h3>
            <p>
              Moving identity, task state, and tool routing out of the prompt and into OS-level constructs. 
              The Phylactery is a cryptographically chained identity log.
            </p>
          </div>
          <div className={`${styles.card} glass`}>
            <h3>Path-Dependent Memory</h3>
            <p>
              MYELIN replaces flat vector stores with a sparse graph whose edges carry semantic similarity, 
              co-activation, and reward signals.
            </p>
          </div>
          <div className={`${styles.card} glass`}>
            <h3>Cognitive Control</h3>
            <p>
              ADCCL forces the system to externalize its intent into a Goal Contract and Claim Budget 
              before any generation occurs.
            </p>
          </div>
        </div>
      </section>

      {/* New section to display backend status */}
      <section className={styles.backendStatus}>
        <h2 className={styles.sectionTitle}>Backend Status</h2>
        {loading && <p>Loading backend status...</p>}
        {error && <p className={styles.error}>Error: {error}</p>}
        {agentStatus && memoryStatus && identityStatus && (
          <div className={styles.statusGrid}>
            <div className={`${styles.statusCard} glass`}>
              <h3>Agent Status</h3>
              <p><strong>Status:</strong> {agentStatus.status}</p>
              <p><strong>Layer:</strong> {agentStatus.layer}</p>
              {agentStatus.user && <p><strong>User:</strong> {agentStatus.user}</p>}
            </div>
            <div className={`${styles.statusCard} glass`}>
              <h3>Memory Status</h3>
              <p><strong>Entries:</strong> {memoryStatus.total_entries}</p>
              <p><strong>Layer:</strong> {memoryStatus.layer}</p>
            </div>
            <div className={`${styles.statusCard} glass`}>
              <h3>Identity Status</h3>
              <p><strong>ID:</strong> {identityStatus.id}</p>
              <p><strong>Status:</strong> {identityStatus.status}</p>
              <p><strong>Layer:</strong> {identityStatus.layer}</p>
            </div>
          </div>
        )}
        {/* Button to demonstrate running a task */}
        <div className={styles.actionButtonContainer}>
            <button onClick={handleRunTask} className={styles.runTaskButton}>
                Run Agent Task Example
            </button>
        </div>
      </section>

      <footer className={styles.footer}>
        <p>© 2026 Ωmegα Architecture — Engineered by Ryan Wayne Yett</p>
        <p className={styles.mono}>r.w.f.y — Sovereign Mode Active</p>
      </footer>
    </main>
  );
}

