file.content:
.main {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.hero {
  display: flex;
  flex-direction: column;
  gap: 2rem;
  padding-top: 2rem;
}

.intro {
  margin-top: 4rem;
}

.introGrid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
}

.card {
  padding: 2.5rem;
  border-radius: 1rem;
  transition: transform 0.3s ease;
}

.card:hover {
  transform: translateY(-5px);
  border-color: rgba(255, 255, 255, 0.2);
}

.card h3 {
  font-size: 1.5rem;
  margin-bottom: 1rem;
  color: var(--omega-cyan);
}

.card p {
  color: #888;
  font-size: 1rem;
}

/* Backend Status Section Styles */
.backendStatus {
  margin-top: 6rem;
  padding: 4rem 1.5rem;
  background-color: rgba(0, 0, 0, 0.1); /* Subtle dark background */
  border-radius: 1.5rem;
}

.sectionTitle {
  text-align: center;
  font-size: 2.2rem;
  margin-bottom: 3rem;
  background: linear-gradient(to right, var(--omega-cyan), var(--sovereign-gold));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.statusGrid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 2rem;
  margin-bottom: 3rem;
}

.statusCard {
  padding: 2rem;
  border-radius: 1rem;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.statusCard:hover {
  transform: translateY(-8px);
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.3);
}

.statusCard h3 {
  font-size: 1.3rem;
  color: var(--sovereign-gold);
  margin-bottom: 1rem;
}

.statusCard p {
  color: #ccc;
  font-size: 1rem;
  margin-bottom: 0.7rem;
}

.statusCard p strong {
  color: var(--omega-cyan);
}

.error {
  color: #ff6b6b;
  font-weight: bold;
}

.actionButtonContainer {
  display: flex;
  justify-content: center;
  margin-top: 2rem;
}

.runTaskButton {
  padding: 0.8rem 2rem;
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--background);
  background-color: var(--omega-cyan);
  border: none;
  border-radius: 0.5rem;
  cursor: pointer;
  transition: background-color 0.3s ease, transform 0.2s ease;
  box-shadow: 0 5px 15px rgba(0, 255, 255, 0.3);
}

.runTaskButton:hover {
  background-color: var(--omega-blue);
  transform: translateY(-2px);
}

.footer {
  padding: 6rem 2rem 4rem;
  text-align: center;
  color: #444;
  font-size: 0.9rem;
}

.footer p {
  margin-bottom: 0.5rem;
}

.mono {
  font-family: var(--font-mono);
  color: #222;
  text-transform: uppercase;
  letter-spacing: 0.3em;
}

