  flex: 1;
  padding: 0.9rem 1rem;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 0.6rem;
  color: var(--foreground);
  font-family: var(--font-sans);
  font-size: 1rem;
  outline: none;
  transition: border-color 0.2s ease;
}

.memInput:focus {
  border-color: var(--sovereign-gold);
}

.submitBtn {
  padding: 0.8rem 1.8rem;
  font-size: 1rem;
  font-weight: 600;
  color: #000;
  background: var(--omega-cyan);
  border: none;
  border-radius: 0.6rem;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.2s ease, transform 0.15s ease;
}

.submitBtn:hover:not(:disabled) {
  background: var(--sovereign-gold);
  transform: translateY(-1px);
}

.submitBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.chatResponse {
  margin-top: 1.5rem;
  padding: 1.5rem;
  border-radius: 0.8rem;
}

.chatMeta {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  margin-bottom: 0.75rem;
}

.chatText {
  color: var(--foreground);
  line-height: 1.7;
  white-space: pre-wrap;
}

/* Memory section */
.memorySection {
  margin-top: 4rem;
  padding: 4rem 1.5rem;
  border-radius: 1.5rem;
  background: rgba(0, 0, 0, 0.1);
}

.memHits {
  margin-top: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.memHit {
  padding: 1.25rem 1.5rem;
  border-radius: 0.7rem;
}

.hitMeta {
  display: flex;
  gap: 0.6rem;
  align-items: center;
  margin-bottom: 0.6rem;
}

.memContent {
  color: #bbb;
  font-size: 0.9rem;
  line-height: 1.6;
  white-space: pre-wrap;
  max-height: 8rem;
  overflow: hidden;
  text-overflow: ellipsis;
}

